const items = $input.all();
const data = items[0].json.body || items[0].json;

const peticao = data.peticao;
const texto = data.texto_processo;

if (!peticao || !texto) {
  throw new Error('Campos obrigatórios: peticao, texto_processo');
}

// Truncar texto se muito grande
const textoTruncado = texto.length > 900000 ? texto.substring(0, 900000) : texto;

const PROMPT_VERIFICACAO = `Você é um verificador forense de petições médico-judiciais. Seu trabalho é garantir que NENHUMA afirmação factual na petição seja inventada.

REGRAS ESTRITAS:
1. Para CADA afirmação factual na petição, busque evidência no texto do processo
2. CONFIRMADO: dado encontrado no texto, com citação exata do trecho onde aparece
3. NAO_ENCONTRADO: dado não aparece no texto (pode ter sido inventado pela IA)
4. DIVERGENTE: dado aparece mas com valor/nome/data diferente
5. REFERENCIA_LEGAL: artigo de lei ou resolução (verificar se a citação parece correta)
6. DADO_FIXO: dado do perito (CRM 92.148, CPF, email contato@stemmia.com.br) — sempre correto, não verificar

CATEGORIAS DE AFIRMAÇÃO:
- FACTUAL: nomes, datas, valores, números de processo, IDs de documentos, diagnósticos, CIDs
- LEGAL: artigos de lei, resoluções, súmulas citadas
- FIXO: dados do próprio perito (sempre corretos)

ATENÇÃO ESPECIAL:
- IDs de documentos do PJe (números de ~11 dígitos): VERIFICAR se aparecem no texto
- Nomes de partes: VERIFICAR grafia exata
- Valores monetários: VERIFICAR se coincidem
- Datas: VERIFICAR se são as mesmas
- CIDs: VERIFICAR se o código corresponde à descrição

Responda EXCLUSIVAMENTE em JSON válido com esta estrutura:
{
  "resumo": {
    "total": <número total de afirmações verificadas>,
    "confirmadas": <quantidade>,
    "nao_encontradas": <quantidade>,
    "divergentes": <quantidade>,
    "referencias_legais": <quantidade>,
    "dados_fixos": <quantidade>,
    "score_percentual": "<XX>%",
    "parecer": "APROVADO|APROVADO_COM_RESSALVAS|REPROVADO"
  },
  "itens": [
    {
      "id": 1,
      "afirmacao": "texto da afirmação encontrada na petição",
      "categoria": "FACTUAL|LEGAL|FIXO",
      "status": "CONFIRMADO|NAO_ENCONTRADO|DIVERGENTE",
      "evidencia": "trecho exato do processo que confirma ou contradiz",
      "localizacao": "seção/contexto onde foi encontrado no processo",
      "observacao": "se divergente, explicar a divergência"
    }
  ]
}

CRITÉRIOS DE PARECER:
- APROVADO: 0 divergentes E 0 não encontrados
- APROVADO_COM_RESSALVAS: 0 divergentes E ≤3 não encontrados (podem ser dados que precisam preencher manualmente)
- REPROVADO: qualquer divergente OU >3 não encontrados`;

const promptCompleto = PROMPT_VERIFICACAO + '\n\n---\n\nPETIÇÃO A VERIFICAR:\n\n' + peticao + '\n\n---\n\nTEXTO ORIGINAL DO PROCESSO:\n\n' + textoTruncado;

return [{
  json: {
    peticao,
    texto_length: texto.length,
    prompt_completo: promptCompleto
  }
}];

// === GEMINI FALLBACK AUTOMÁTICO ===
// Tenta modelos em ordem até um funcionar
// Se todos falharem, lança erro com detalhes

const GEMINI_KEY = 'AIzaSyA9Gh9JYW4VEiKVlmCR0ziUD3umK9pJYWQ';
const MODELOS = ["gemini-2.5-flash", "gemini-2.5-flash-lite", "gemini-2.5-pro"];
const TELEGRAM_TOKEN = '8603024374:AAH81RHxIBwOsTaDI87nM7ap2DHcuE3xnxA';
const TELEGRAM_CHAT = '8397602236';

const promptCompleto = $json.prompt_completo;
const temperature = 0.2;
const maxTokens = 8192;

async function chamarGemini(modelo, prompt, temp, tokens) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelo}:generateContent?key=${GEMINI_KEY}`;
  const body = JSON.stringify({
    contents: [{parts: [{text: prompt}]}],
    generationConfig: {temperature: temp, maxOutputTokens: tokens}
  });

  const resp = await fetch(url, {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: body,
    signal: AbortSignal.timeout(120000)
  });

  const data = await resp.json();

  if (data.error) {
    const code = data.error.code || resp.status;
    throw new Error(`${code}: ${data.error.message}`);
  }

  if (!data.candidates || data.candidates.length === 0) {
    throw new Error('Resposta vazia');
  }

  if (data.candidates[0].finishReason === 'SAFETY') {
    throw new Error('Bloqueado por filtro de segurança');
  }

  return data;
}

async function notificarTelegram(msg) {
  try {
    await fetch(`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({chat_id: TELEGRAM_CHAT, text: msg})
    });
  } catch(e) {}
}

let resultado = null;
let modeloUsado = '';
const erros = [];

for (const modelo of MODELOS) {
  try {
    resultado = await chamarGemini(modelo, promptCompleto, temperature, maxTokens);
    modeloUsado = modelo;
    break;
  } catch (e) {
    erros.push(`${modelo}: ${e.message}`);
    if (e.message.includes('429') || e.message.includes('RESOURCE_EXHAUSTED') || e.message.includes('quota')) {
      await notificarTelegram(`⚠️ Gemini ${modelo} sem quota. Tentando próximo...`);
      continue;
    }
    // Erro não relacionado a quota — tentar próximo mesmo assim
    continue;
  }
}

if (!resultado) {
  await notificarTelegram(`❌ TODOS os modelos Gemini falharam:\n${erros.join('\n')}`);
  throw new Error('Todos os modelos falharam: ' + erros.join(' | '));
}

// Se usou modelo diferente do primeiro, notificar
if (modeloUsado !== MODELOS[0]) {
  await notificarTelegram(`🔄 Modelo trocado: ${modeloUsado} (primário indisponível)`);
}

const texto = resultado.candidates[0].content.parts[0].text;

return [{
  json: {
    ...($input.all()[0].json),
    gemini_response: resultado,
    gemini_text: texto,
    modelo_usado: modeloUsado,
    fallback: modeloUsado !== MODELOS[0]
  }
}];

// Texto já extraído pelo nó de fallback
const sintese = $input.all()[0].json.gemini_text;
const modeloUsado = $input.all()[0].json.modelo_usado || 'desconhecido';

const response = $input.all()[0].json;



const textoResposta = response.candidates[0].content.parts[0].text;

// Parsear JSON
let verificacao;
try {
  verificacao = JSON.parse(textoResposta);
} catch (e) {
  // Tentar extrair JSON de dentro de markdown code block
  const jsonMatch = textoResposta.match(/```json?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    verificacao = JSON.parse(jsonMatch[1]);
  } else {
    throw new Error('Resposta do Gemini não é JSON válido: ' + textoResposta.substring(0, 500));
  }
}

const resumo = verificacao.resumo;
const itens = verificacao.itens || [];

// Gerar relatório markdown
const meses = ['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
const hoje = new Date();
const dataExtenso = hoje.getDate() + ' de ' + meses[hoje.getMonth()] + ' de ' + hoje.getFullYear();

let relatorio = `# RELATÓRIO DE VERIFICAÇÃO\n\n`;
relatorio += `**Data:** ${dataExtenso}\n\n`;
relatorio += `## RESUMO\n\n`;
relatorio += `| Métrica | Valor |\n|---------|-------|\n`;
relatorio += `| Total de afirmações | ${resumo.total} |\n`;
relatorio += `| Confirmadas | ${resumo.confirmadas} |\n`;
relatorio += `| Não encontradas | ${resumo.nao_encontradas} |\n`;
relatorio += `| Divergentes | ${resumo.divergentes} |\n`;
relatorio += `| Referências legais | ${resumo.referencias_legais} |\n`;
relatorio += `| Dados fixos | ${resumo.dados_fixos} |\n`;
relatorio += `| **Score** | **${resumo.score_percentual}** |\n`;
relatorio += `| **Parecer** | **${resumo.parecer}** |\n\n`;

// Itens divergentes (críticos)
const divergentes = itens.filter(i => i.status === 'DIVERGENTE');
if (divergentes.length > 0) {
  relatorio += `## ⚠️ ITENS DIVERGENTES (CRÍTICO)\n\n`;
  divergentes.forEach(item => {
    relatorio += `${item.id}. "${item.afirmacao}"\n`;
    relatorio += `   - **Status:** DIVERGENTE\n`;
    relatorio += `   - **Evidência:** ${item.evidencia}\n`;
    relatorio += `   - **Observação:** ${item.observacao}\n\n`;
  });
}

// Itens não encontrados
const naoEncontrados = itens.filter(i => i.status === 'NAO_ENCONTRADO');
if (naoEncontrados.length > 0) {
  relatorio += `## ❓ ITENS NÃO ENCONTRADOS\n\n`;
  naoEncontrados.forEach(item => {
    relatorio += `${item.id}. "${item.afirmacao}"\n`;
    relatorio += `   - **Categoria:** ${item.categoria}\n`;
    relatorio += `   - **Observação:** ${item.observacao || 'Dado não localizado no texto do processo'}\n\n`;
  });
}

// Todos os itens confirmados (resumido)
const confirmados = itens.filter(i => i.status === 'CONFIRMADO');
if (confirmados.length > 0) {
  relatorio += `## ✅ ITENS CONFIRMADOS (${confirmados.length})\n\n`;
  confirmados.forEach(item => {
    relatorio += `${item.id}. "${item.afirmacao}" — ${item.localizacao || 'confirmado'}\n`;
  });
}

return [{
  json: {
    relatorio_md: relatorio,
    verificacao_json: verificacao,
    parecer: resumo.parecer,
    score: resumo.score_percentual,
    total: resumo.total,
    confirmadas: resumo.confirmadas,
    nao_encontradas: resumo.nao_encontradas,
    divergentes: resumo.divergentes
  }
}];
